import { ktService } from '../../services/kt/ktService';
import type {
  AdvancePaymentDto,
  CashVoucherDto,
  JournalEntryDto,
  PurchaseInvoiceDto,
} from '../../services/kt/models';
import { documentTypeLabel } from '../../utils/reportDocumentDrillDown';
import { formatDateLocal, formatVnd } from '../../utils/formatters';

export type ReportDocumentPreview = {
  documentType: string;
  typeLabel: string;
  code: string;
  date?: string;
  description?: string;
  amount?: number;
  status?: string;
  lines: { label: string; debit?: number; credit?: number; amount?: number }[];
};

export async function loadReportDocumentPreview(
  documentType: string,
  documentId: string,
): Promise<ReportDocumentPreview> {
  switch (documentType) {
    case 'CashReceipt':
    case 'CashPayment': {
      const dto: CashVoucherDto =
        documentType === 'CashReceipt'
          ? await ktService.getReceipt(documentId)
          : await ktService.getPayment(documentId);
      return {
        documentType,
        typeLabel: documentTypeLabel(documentType),
        code: dto.code,
        date: formatDateLocal(dto.voucherDate),
        description: dto.description,
        amount: dto.amount,
        status: dto.status,
        lines: (dto.lines ?? []).map((l, i) => ({
          label: l.description ?? `${l.debitAccountCode} / ${l.creditAccountCode}`,
          amount: l.amount,
        })),
      };
    }
    case 'JournalEntry': {
      const dto: JournalEntryDto = await ktService.getJournalEntry(documentId);
      return {
        documentType,
        typeLabel: documentTypeLabel(documentType),
        code: dto.code,
        date: formatDateLocal(dto.entryDate),
        description: dto.description,
        status: dto.status,
        lines: (dto.lines ?? []).map((l, i) => ({
          label: l.description ?? `${l.debitAccountCode} / ${l.creditAccountCode}`,
          amount: l.amount,
        })),
      };
    }
    case 'PurchaseInvoice': {
      const dto: PurchaseInvoiceDto = await ktService.getPurchaseInvoice(documentId);
      return {
        documentType,
        typeLabel: documentTypeLabel(documentType),
        code: dto.code,
        date: formatDateLocal(dto.invoiceDate),
        description: dto.description,
        amount: dto.totalAmount,
        status: dto.status,
        lines: (dto.lines ?? []).slice(0, 20).map((l, i) => ({
          label: l.materialCode ?? `Dòng ${i + 1}`,
          amount: l.amount,
        })),
      };
    }
    case 'AdvancePayment': {
      const dto: AdvancePaymentDto = await ktService.getAdvancePayment(documentId);
      return {
        documentType,
        typeLabel: documentTypeLabel(documentType),
        code: dto.code,
        date: formatDateLocal(dto.voucherDate),
        description: dto.description,
        amount: dto.amount,
        status: dto.status,
        lines: (dto.lines ?? []).map((l, i) => ({
          label: l.description ?? `Dòng ${i + 1}`,
          amount: l.amount,
        })),
      };
    }
    default:
      throw new Error(`Unsupported document type: ${documentType}`);
  }
}

export function formatPreviewAmount(amount?: number): string {
  return amount != null ? formatVnd(amount) : '—';
}
