import React, { useEffect, useState } from 'react';
import { Button, Slideout } from '@linm-soft/common-components';
import {
  formatPreviewAmount,
  loadReportDocumentPreview,
  type ReportDocumentPreview,
} from './loadReportDocumentPreview';
import styles from './ReportSourceDocumentSlideout.module.css';

export type ReportSourceDocumentSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  documentType: string | null;
  documentId: string | null;
  voucherCode?: string;
  title: string;
  closeLabel: string;
  openFullLabel: string;
  loadErrorLabel: string;
  onOpenFullPage: () => void;
  testIdPrefix: string;
};

export const ReportSourceDocumentSlideout: React.FC<ReportSourceDocumentSlideoutProps> = ({
  isOpen,
  onClose,
  documentType,
  documentId,
  voucherCode,
  title,
  closeLabel,
  openFullLabel,
  loadErrorLabel,
  onOpenFullPage,
  testIdPrefix,
}) => {
  const [preview, setPreview] = useState<ReportDocumentPreview | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(false);

  useEffect(() => {
    if (!isOpen || !documentType || !documentId) {
      setPreview(null);
      setError(false);
      return;
    }
    let cancelled = false;
    setLoading(true);
    setError(false);
    const t = setTimeout(() => {
      loadReportDocumentPreview(documentType, documentId)
        .then(data => {
          if (!cancelled) setPreview(data);
        })
        .catch(() => {
          if (!cancelled) setError(true);
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [isOpen, documentType, documentId]);

  const slideoutTitle = preview
    ? `${title}: ${preview.code}`
    : voucherCode
      ? `${title}: ${voucherCode}`
      : title;

  const footer = (
    <div className={styles.footerBar}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-slideout-close`}>
        {closeLabel}
      </Button>
      <Button
        variant="primary"
        onClick={onOpenFullPage}
        disabled={!documentType || !documentId}
        data-testid={`${testIdPrefix}-slideout-open-full`}
      >
        {openFullLabel}
      </Button>
    </div>
  );

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title={slideoutTitle}
      width="min(960px, 92vw)"
      customFooter={footer}
      data-testid={`${testIdPrefix}-document-slideout`}
    >
      {loading && (
        <div className={styles.loading} data-testid={`${testIdPrefix}-slideout-loading`}>
          <i className="fas fa-spinner fa-spin" /> Đang tải…
        </div>
      )}
      {error && !loading && (
        <div className={styles.error}>{loadErrorLabel}</div>
      )}
      {preview && !loading && !error && (
        <div className={styles.body}>
          <div className={styles.meta}>
            <div className={styles.metaItem}>
              <label>Loại</label>
              <span>{preview.typeLabel}</span>
            </div>
            <div className={styles.metaItem}>
              <label>Số CT</label>
              <span><code>{preview.code}</code></span>
            </div>
            {preview.date && (
              <div className={styles.metaItem}>
                <label>Ngày</label>
                <span>{preview.date}</span>
              </div>
            )}
            {preview.status && (
              <div className={styles.metaItem}>
                <label>Trạng thái</label>
                <span>{preview.status}</span>
              </div>
            )}
            {preview.amount != null && (
              <div className={styles.metaItem}>
                <label>Số tiền</label>
                <span>{formatPreviewAmount(preview.amount)}</span>
              </div>
            )}
          </div>
          {preview.description && (
            <div className={styles.metaItem}>
              <label>Diễn giải</label>
              <span>{preview.description}</span>
            </div>
          )}
          {preview.lines.length > 0 && (
            <table className={styles.linesTable}>
              <thead>
                <tr>
                  <th>Diễn giải</th>
                  <th className={styles.colRight}>Nợ</th>
                  <th className={styles.colRight}>Có</th>
                  <th className={styles.colRight}>Số tiền</th>
                </tr>
              </thead>
              <tbody>
                {preview.lines.map((line, i) => (
                  <tr key={i}>
                    <td>{line.label}</td>
                    <td className={styles.colRight}>
                      {line.debit != null ? formatPreviewAmount(line.debit) : '—'}
                    </td>
                    <td className={styles.colRight}>
                      {line.credit != null ? formatPreviewAmount(line.credit) : '—'}
                    </td>
                    <td className={styles.colRight}>
                      {line.amount != null ? formatPreviewAmount(line.amount) : '—'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </Slideout>
  );
};
